import{_ as t,o as i,c as r,a2 as o}from"./chunks/framework.il0noOp3.js";const m=JSON.parse('{"title":"Required Permissions","description":"ARM RBAC and Microsoft Graph permissions required by AzureScout.","frontmatter":{"description":"ARM RBAC and Microsoft Graph permissions required by AzureScout."},"headers":[],"relativePath":"permissions.md","filePath":"permissions.md"}'),a={name:"permissions.md"};function d(s,e,n,l,c,p){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="required-permissions" tabindex="-1">Required Permissions <a class="header-anchor" href="#required-permissions" aria-label="Permalink to &quot;Required Permissions&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>AzureScout requires two categories of permissions:</p><ol><li><strong>ARM (Azure Resource Manager)</strong> — RBAC role assignments on subscriptions</li><li><strong>Microsoft Graph API</strong> — Application or delegated permissions for Entra ID data</li></ol><h2 id="arm-permissions" tabindex="-1">ARM Permissions <a class="header-anchor" href="#arm-permissions" aria-label="Permalink to &quot;ARM Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Scope</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Reader</code></td><td>Subscription(s)</td><td>Enumerate resources, read properties</td></tr><tr><td><code>Reader</code> on role assignments</td><td>Subscription(s)</td><td>Read RBAC role assignments (optional — Warn if missing)</td></tr></tbody></table><p>The pre-flight checker validates:</p><ul><li><strong>Subscription Enumeration</strong> — Can <code>Get-AzSubscription</code> return at least one subscription? (Fail if not)</li><li><strong>Role Assignment Read</strong> — Can <code>Get-AzRoleAssignment</code> read roles on the first subscription? (Warn if not — non-blocking)</li></ul><h2 id="microsoft-graph-permissions" tabindex="-1">Microsoft Graph Permissions <a class="header-anchor" href="#microsoft-graph-permissions" aria-label="Permalink to &quot;Microsoft Graph Permissions&quot;">​</a></h2><p>The following Microsoft Graph API permissions are required for Entra ID inventory:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Organization.Read.All</code></td><td>Application or Delegated</td><td>Read tenant organization details</td></tr><tr><td><code>User.Read.All</code></td><td>Application or Delegated</td><td>Read all user profiles</td></tr><tr><td><code>Group.Read.All</code></td><td>Application or Delegated</td><td>Read all groups and memberships</td></tr><tr><td><code>Application.Read.All</code></td><td>Application or Delegated</td><td>Read all app registrations and service principals</td></tr><tr><td><code>Directory.Read.All</code></td><td>Application or Delegated</td><td>Read directory roles, administrative units, domains</td></tr><tr><td><code>Policy.Read.All</code></td><td>Application or Delegated</td><td>Read conditional access policies, named locations</td></tr><tr><td><code>RoleManagement.Read.All</code></td><td>Application or Delegated</td><td>Read PIM role assignments and eligible assignments</td></tr><tr><td><code>IdentityProvider.Read.All</code></td><td>Application or Delegated</td><td>Read authentication methods and identity providers</td></tr><tr><td><code>Policy.Read.ConditionalAccess</code></td><td>Application or Delegated</td><td>Read conditional access policies (optional — Warn only)</td></tr></tbody></table><h2 id="pre-flight-validation" tabindex="-1">Pre-flight Validation <a class="header-anchor" href="#pre-flight-validation" aria-label="Permalink to &quot;Pre-flight Validation&quot;">​</a></h2><p>The <code>Test-AZSCPermissions</code> function runs automatically before extraction (unless <code>-SkipPermissionCheck</code> is set):</p><table tabindex="0"><thead><tr><th>Check</th><th>Severity</th><th>Behavior</th></tr></thead><tbody><tr><td>ARM: Subscription Enumeration</td><td><strong>Fail</strong></td><td>Stops ARM extraction if no subscriptions accessible</td></tr><tr><td>ARM: Role Assignment Read</td><td><strong>Warn</strong></td><td>Continues — some RBAC data may be missing</td></tr><tr><td>Graph: Organization Read</td><td><strong>Fail</strong></td><td>Stops Entra extraction if organization endpoint is inaccessible</td></tr><tr><td>Graph: User Read</td><td><strong>Fail</strong></td><td>Stops Entra extraction if user endpoint is inaccessible</td></tr><tr><td>Graph: Conditional Access Policies</td><td><strong>Warn</strong></td><td>Continues — CA policy data may be missing</td></tr></tbody></table><h2 id="scope-based-gating" tabindex="-1">Scope-Based Gating <a class="header-anchor" href="#scope-based-gating" aria-label="Permalink to &quot;Scope-Based Gating&quot;">​</a></h2><p>Permission checks respect the <code>-Scope</code> parameter:</p><ul><li><code>ArmOnly</code> — Only ARM checks run (Graph checks are skipped entirely)</li><li><code>EntraOnly</code> — Only Graph checks run (ARM checks are skipped entirely)</li><li><code>All</code> — Both ARM and Graph checks run</li></ul><h2 id="remediation" tabindex="-1">Remediation <a class="header-anchor" href="#remediation" aria-label="Permalink to &quot;Remediation&quot;">​</a></h2><p>If the permission checker reports failures:</p><ol><li>For ARM: Ensure <code>Reader</code> role is assigned on target subscriptions</li><li>For Graph: Grant the required Microsoft Graph API permissions to your app registration or user account</li><li>Re-run with the appropriate credentials</li></ol>',20)])])}const u=t(a,[["render",d]]);export{m as __pageData,u as default};
